import{d as n}from"./app.92cfecb8.js";import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";const s={},e=n(`<h2 id="css-transition" tabindex="-1"><a class="header-anchor" href="#css-transition" aria-hidden="true">#</a> css transition</h2><p>Transitions are when the browser animates from one state to another (A to B). They\u2019re usually triggered by an action such <code>hovering over an element</code>, or <code>adding or removing a class using JavaScript</code>.</p><p>Transitions take place in the browser when an element changes from one state to another. The browser draws the frames between each state automatically to create movement.</p><h3 id="transition" tabindex="-1"><a class="header-anchor" href="#transition" aria-hidden="true">#</a> transition</h3><p>Notice the transition property to the first button reference in the CSS state. This tells the browser to apply a transition to any change of state such as on hover as well as when changing back from the hover state.</p><p>If we applied the transition property to the hover state only, it would only transition to the hover state but not back.</p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token selector">button</span> <span class="token punctuation">{</span>
    <span class="token property">background</span><span class="token punctuation">:</span> white<span class="token punctuation">;</span>
    <span class="token property">transition</span><span class="token punctuation">:</span> background 0.5s linear<span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token selector">button:hover</span> <span class="token punctuation">{</span>
    <span class="token property">background</span><span class="token punctuation">:</span> green<span class="token punctuation">;</span>
    <span class="token comment">/*transition: background 0.5s linear;*/</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="css-animations" tabindex="-1"><a class="header-anchor" href="#css-animations" aria-hidden="true">#</a> css Animations</h2><p>Animations are more involved, and let you create sequences of animations with as many keyframes as you need along the way. They trigger automatically, and can loop.</p><h3 id="animation-delay" tabindex="-1"><a class="header-anchor" href="#animation-delay" aria-hidden="true">#</a> animation-delay</h3><ul><li><p>If the animation loops, <strong>the delay does not apply each time it loops.</strong> The delay only applies to when the animation is applied to the element.</p></li><li><p>You can give this property a negative value such as -1s. This would cause the animation to start as if a second has <strong>already elapsed</strong>.</p></li></ul><h3 id="animation-fill-mode" tabindex="-1"><a class="header-anchor" href="#animation-fill-mode" aria-hidden="true">#</a> animation-fill-mode</h3><p>By default, an animation will play and then the element <strong>returns to its normal state</strong>.Using animation-fill-mode we can have the animation \u201Cstick\u201D at either the end or beginning state.</p><p>Using the value <code>forwards</code> tells the animation to finish and stay on the last keyframe. The value <code>backwards</code> returns to the first keyframe when the animation finishes.</p><h3 id="animation-play-state" tabindex="-1"><a class="header-anchor" href="#animation-play-state" aria-hidden="true">#</a> animation-play-state</h3><p>If you ever need to pause or resume an animation, this property lets you do so. It takes the values of <code>running</code> or <code>paused</code>, with the default being <code>running</code>. One idea might be to set this value on an animation <strong>using JavaScript</strong>.</p><h3 id="animation-timing-function" tabindex="-1"><a class="header-anchor" href="#animation-timing-function" aria-hidden="true">#</a> animation-timing-function</h3><p>This takes the same values the timing function property in transitions, but behaves a little differently. While a timing function, such as ease-out <strong>applies to the entire transition</strong>, the timing function of an animation a<strong>pplies between each keyframe.</strong></p><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token comment">/*animation-timing-function : ease-out;*/</span>
<span class="token atrule"><span class="token rule">@keyframes</span> foo</span> <span class="token punctuation">{</span>
    <span class="token selector">0%</span> <span class="token punctuation">{</span>
        <span class="token comment">/* Animation starts fast and ease-out makes it slow down before 50% */</span>
    <span class="token punctuation">}</span>
    <span class="token selector">50%</span> <span class="token punctuation">{</span>
        <span class="token comment">/* Again, starts fast and slows toward 100% */</span>
    <span class="token punctuation">}</span>
    <span class="token selector">100%</span> <span class="token punctuation">{</span>
        <span class="token comment">/* fin */</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token comment">/*so we usually define animation-timing-function on a per-keyframe basis*/</span>
<span class="token atrule"><span class="token rule">@keyframes</span> my-animation</span> <span class="token punctuation">{</span>
    <span class="token selector">0%</span> <span class="token punctuation">{</span>
        <span class="token comment">/*...*/</span>
        <span class="token property">animation-timing-function</span><span class="token punctuation">:</span> linear<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token selector">50%</span> <span class="token punctuation">{</span>
        <span class="token comment">/*...*/</span>
        <span class="token property">animation-timing-function</span><span class="token punctuation">:</span> ease-out<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><h3 id="things-to-look-out-for" tabindex="-1"><a class="header-anchor" href="#things-to-look-out-for" aria-hidden="true">#</a> Things to look out for</h3><ul><li>keywords <code>from</code> and <code>to</code> is simple an alternate way of writing <code>0%</code> and <code>100%</code></li><li>You may have noticed that sometimes more than one percentage value is used on the same line. This is a way to <strong>have the animation pause for a while</strong>, or hold a particular state.</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token comment">/*This example will have the element start with an opacity of 0, 
and stay invisible until 20% through the animation*/</span>
<span class="token atrule"><span class="token rule">@keyframes</span> name</span> <span class="token punctuation">{</span>
    <span class="token selector">0%, 20%</span> <span class="token punctuation">{</span>
        <span class="token property">opacity</span><span class="token punctuation">:</span> 0<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
    <span class="token selector">100%</span> <span class="token punctuation">{</span>
        <span class="token property">opacity</span><span class="token punctuation">:</span> 1<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><ul><li>Lastly, you can <strong>omit the 0% keyframe</strong> and the browser will take the element\u2019s style as implied. For example, to have something fade away, we don\u2019t necessarily have to give it a starting opacity of 1 (assuming the element is already visible)</li></ul><div class="language-css ext-css line-numbers-mode"><pre class="language-css"><code><span class="token atrule"><span class="token rule">@keyframes</span> name</span> <span class="token punctuation">{</span>
    <span class="token selector">100%</span> <span class="token punctuation">{</span>
        <span class="token property">opacity</span><span class="token punctuation">:</span> 0<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>If a keyframe rule doesn&#39;t specify the start or end states of the animation (that is, <code>0%/from</code> and <code>100%/to</code>), browsers will use the element&#39;s existing styles for the start/end states. This can be used to animate an element from its initial state and back.</li></ul><h2 id="multiple-animations" tabindex="-1"><a class="header-anchor" href="#multiple-animations" aria-hidden="true">#</a> Multiple animations</h2>`,26);function t(o,i){return e}var r=a(s,[["render",t]]);export{r as default};
